module counter_8bit(reset_signal, rst, en, count);
    input reset_signal;
    input rst;
    input en;
    output reg [7:0] count;

    always @(posedge reset_signal or posedge rst) begin
        if (rst) begin
            count <= 0;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule
